import{_ as a,o as t,c as o,a1 as n}from"./chunks/framework.BwhMLafE.js";const h=JSON.parse('{"title":"Grammar Writing Guidelines","description":"","frontmatter":{},"headers":[],"relativePath":"grammar_guidelines.md","filePath":"grammar_guidelines.md"}'),i={name:"grammar_guidelines.md"};function r(s,e,l,c,d,p){return t(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="grammar-writing-guidelines" tabindex="-1">Grammar Writing Guidelines <a class="header-anchor" href="#grammar-writing-guidelines" aria-label="Permalink to &quot;Grammar Writing Guidelines&quot;">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#1-file-structure--rule-syntax-grm-files">1. File Structure &amp; Rule Syntax (<code>.grm</code> files)</a></li><li><a href="#2-variable-naming--ast-generation">2. Variable Naming &amp; AST Generation</a></li><li><a href="#3-terminal-symbols">3. Terminal Symbols</a></li><li><a href="#4-procedure-hooks-procedure_name">4. Procedure Hooks (<code>@procedure_name</code>)</a></li><li><a href="#5-explicit-syntax-recovery-">5. Explicit Syntax Recovery (<code>!</code>)</a></li></ul><hr><p>This guide details the syntax, conventions, and compile-time annotations supported by this repository&#39;s parser generators (LL and LR).</p><hr><h2 id="_1-file-structure-rule-syntax-grm-files" tabindex="-1">1. File Structure &amp; Rule Syntax (<code>.grm</code> files) <a class="header-anchor" href="#_1-file-structure-rule-syntax-grm-files" aria-label="Permalink to &quot;1. File Structure &amp; Rule Syntax (\`.grm\` files)&quot;">​</a></h2><ul><li><p><strong>Rule Structure:</strong> Each grammar rule is defined by the LHS (Left-Hand Side) variable symbol on a single line, followed by its alternative productions.</p></li><li><p><strong>Unique Rule Headers:</strong> Each variable must have exactly one LHS header. Put all of its alternatives on consecutive <code>|</code> lines beneath that header; declaring the same LHS again is an error.</p></li><li><p><strong>Alternation:</strong> Each alternative production must start with a pipe character <code>|</code> on a new line, followed by space-separated symbols:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Value</span></span>
<span class="line"><span>| &quot;{&quot; OptionalBlank ObjectMembers OptionalBlank</span></span>
<span class="line"><span>| &quot;null&quot; OptionalBlank</span></span></code></pre></div></li><li><p><strong>Epsilon (Empty Productions):</strong> An empty production is represented by a single pipe <code>|</code> with no trailing symbols:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OptionalBlank</span></span>
<span class="line"><span>| space _OptionalBlankTail</span></span>
<span class="line"><span>|</span></span></code></pre></div></li><li><p><strong>Formatting:</strong> Rules must be separated by at least one blank line. The first variable defined in the file is automatically treated as the parser&#39;s entry point.</p></li></ul><hr><h2 id="_2-variable-naming-ast-generation" tabindex="-1">2. Variable Naming &amp; AST Generation <a class="header-anchor" href="#_2-variable-naming-ast-generation" aria-label="Permalink to &quot;2. Variable Naming &amp; AST Generation&quot;">​</a></h2><p>The parser generator statically configures the Abstract Syntax Tree (AST) node creation based on the naming style of the variable symbols:</p><ul><li><strong>PascalCase Validation:</strong> All variable names must be written in PascalCase. The generator validates this at compile-time.</li><li><strong>AST-Enabled Variables:</strong> Variables starting with a Capital letter (e.g. <code>Value</code>, <code>ObjectMembers</code>) allocate an AST node when matched.</li><li><strong>AST-Suppressed Helper Variables:</strong> Variables starting with an underscore (e.g. <code>_StringContent</code>, <code>_OptionalBlank</code>) are helper rules. The generator completely skips allocating AST nodes for them, optimizing runtime parsing performance and memory footprint.</li></ul><hr><h2 id="_3-terminal-symbols" tabindex="-1">3. Terminal Symbols <a class="header-anchor" href="#_3-terminal-symbols" aria-label="Permalink to &quot;3. Terminal Symbols&quot;">​</a></h2><p>Terminals in rules represent either exact character literals or pre-defined generative character classes:</p><ul><li><strong>Normal Terminals:</strong> Exact character/string matches can be written in one of two quoting styles: <ul><li><strong>Double-quoted:</strong> Wrapped in double quotes (e.g., <code>&quot;{&quot;</code>, <code>&quot;null&quot;</code>, <code>&quot;+&quot;</code>).</li><li><strong>Single-quoted:</strong> Wrapped in single quotes at the start and terminating with the <code>\\x03</code> (0x03) byte (e.g., <code>&#39;&quot;\\x03</code> representing the <code>&quot;</code> character).</li></ul></li><li><strong>Generative Character Terminals:</strong> Unquoted keyword names map to specific sets of ASCII characters: <ul><li><code>digit</code>: Matches <code>&#39;0&#39;-&#39;9&#39;</code></li><li><code>letter</code>: Matches <code>&#39;a&#39;-&#39;z&#39;</code> and <code>&#39;A&#39;-&#39;Z&#39;</code></li><li><code>lowercase_letter</code>: Matches <code>&#39;a&#39;-&#39;z&#39;</code></li><li><code>uppercase_letter</code>: Matches <code>&#39;A&#39;-&#39;Z&#39;</code></li><li><code>whitespace</code>: Matches whitespace characters (<code>\\t</code>, <code>\\n</code>, <code>\\r</code>, <code>\\x0b</code>, <code>\\x0c</code>, <code></code>)</li><li><code>punctuation</code>: Matches standard punctuation characters</li><li><code>character</code>: Matches letters, digits, punctuation, and whitespace</li><li><code>operator</code>: Matches operator symbols (<code>+</code>, <code>*</code>, <code>/</code>, <code>&amp;</code>, <code>|</code>, <code>&gt;</code>, <code>&gt;=</code>, <code>&lt;</code>, <code>&lt;=</code>, <code>=</code>)</li><li><code>new_line</code>: Matches <code>\\n</code></li><li><code>space</code>: Matches space <code>&#39; &#39;</code></li><li><code>block_start</code>: Matches control character <code>\\x01</code> (representing the start of a block when indentation syntax is enabled for the parser, see <a href="./configuration.html#language-configuration">Language Configuration</a> for details)</li><li><code>block_end</code>: Matches control character <code>\\x02</code> (representing the end of a block when indentation syntax is enabled for the parser, see <a href="./configuration.html#language-configuration">Language Configuration</a> for details)</li></ul></li><li><strong>Generative Suffix Exceptions:</strong> Any generative terminal can have exceptions appended as a suffix chain introduced by the <code>^</code> character followed by a normal terminal (e.g., <code>character^&quot;\\n&quot;</code>, <code>character^&#39;&quot;\\x03</code>, or multiple chained exceptions like <code>digit^&quot;1&quot;^&quot;3&quot;</code>). The exception terminal&#39;s characters are excluded from the allowed terminal characters of the generative class.</li></ul><hr><h2 id="_4-procedure-hooks-procedure-name" tabindex="-1">4. Procedure Hooks (<code>@procedure_name</code>) <a class="header-anchor" href="#_4-procedure-hooks-procedure-name" aria-label="Permalink to &quot;4. Procedure Hooks (\`@procedure_name\`)&quot;">​</a></h2><p>Galley provides three explicit hook placements, registered by appending a procedure name with <code>@</code>, and a fourth family of automatic reduction hooks:</p><ol><li><p><strong>LHS Variable Hook:</strong> Attaches to the left-hand-side variable definition, executing whenever this variable is reduced anywhere:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Value@dropChildren</span></span>
<span class="line"><span>| Object OptionalBlank</span></span>
<span class="line"><span>| Array OptionalBlank</span></span></code></pre></div></li><li><p><strong>RHS Symbol Hook:</strong> Attaches to a right-hand-side symbol (either a variable, or a terminal symbol if <code>--ast-for-terminals</code> is active), executing only when matched in that position:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Parent</span></span>
<span class="line"><span>| Value Child@validateChild &quot;]&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Number</span></span>
<span class="line"><span>| digit@recordDigit _PositiveIntegerNumberTail</span></span></code></pre></div></li><li><p><strong>Production Hook:</strong> Attaches to the left-hand-side variable for a specific right-hand-side production. It is placed immediately after the pipe (<code>|</code>) and executes on the resulting left-hand-side node only when that particular production is reduced:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FloatTail</span></span>
<span class="line"><span>|@normalizeFraction &quot;.&quot; PositiveIntegerNumber</span></span>
<span class="line"><span>|</span></span></code></pre></div></li><li><p><strong>Automatic Reduction Hooks:</strong> Exporting conventionally named public procedures from <code>procedures.zig</code> binds them without grammar annotations:</p><ul><li><code>reduction_&lt;SymbolName&gt;_&lt;RhsIndex&gt;</code> runs only for the zero-based production index of that symbol. Indices follow the consecutive <code>|</code> lines beneath the variable&#39;s unique LHS header.</li><li><code>reduction_&lt;SymbolName&gt;</code> runs whenever that symbol produces an AST node.</li><li><code>reduction</code> runs for every eligible variable reduction and AST-enabled terminal match.</li></ul></li></ol><p>Multiple procedures can be chained on any explicit hook target (for example, <code>Number@hook1@hook2</code>). Chaining runs the procedures from left to right; it is not a separate hook kind.</p><p>For each variable reduction, hooks run in this order: RHS occurrence hooks, production hooks, <code>reduction_&lt;SymbolName&gt;_&lt;RhsIndex&gt;</code>, LHS hooks, <code>reduction_&lt;SymbolName&gt;</code>, then the general <code>reduction</code> hook. Each explicit chain runs left to right, and each phase receives the node produced by the preceding phase.</p><p>For an AST-enabled terminal, the occurrence chain runs first, followed by <code>reduction_&lt;SymbolName&gt;</code> and then <code>reduction</code>. Terminal hooks receive <code>args.rule = null</code>. LR generation reports <code>error.AmbiguousProcedureHooks</code> if the parser cannot distinguish occurrences with different chains at the match or reduction point.</p><hr><p>For detailed information on automatic hooks, nested reduction ordering, compiler AST requirements, and how to write hook functions in Zig, see the <a href="./procedures.html">Reduction Procedures User Guide</a>.</p><h2 id="_5-explicit-syntax-recovery" tabindex="-1">5. Explicit Syntax Recovery (<code>!</code>) <a class="header-anchor" href="#_5-explicit-syntax-recovery" aria-label="Permalink to &quot;5. Explicit Syntax Recovery (\`!\`)&quot;">​</a></h2><p>Recovery annotations declare synchronization terminals on an LHS variable, a production, or an RHS variable occurrence:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Statement!^&quot;}&quot;!&quot;;&quot;^@hook</span></span>
<span class="line"><span>|!&quot;,&quot;^ Expression</span></span>
<span class="line"><span>| Block Statement!^&quot;}&quot;</span></span></code></pre></div><ul><li><code>!^&quot;}&quot;</code> resumes immediately before <code>}</code> and preserves the terminal for the surrounding parser state.</li><li><code>!&quot;;&quot;^</code> resumes immediately after <code>;</code> and consumes the terminal.</li><li>Consecutive annotations provide multiple candidates for one target. They must appear before any <code>@</code> hooks on that target.</li><li>Recovery terminals accept the same two quoted exact-terminal forms as normal grammar terminals. Empty terminals, NUL-containing terminals, and generative terminals are invalid.</li><li>An RHS recovery annotation may only attach to a variable occurrence, not a terminal occurrence.</li></ul><p>When error recovery generation is enabled and the grammar has no annotations, Galley uses automatic recovery. The presence of any recovery annotation selects explicit-only recovery for the generated parser; an error outside committed annotated scopes fails immediately without automatic fallback. When recovery generation is disabled, annotations remain in the grammar model but are inert, and generation emits one warning.</p><p>After a mismatch, Galley tries committed scopes from the most specific to the most general: the active RHS occurrence, its selected production, its LHS variable, then enclosing reductions. Within one target it chooses the earliest candidate in the input, then the longest terminal, then source order. A successful recovery preserves the original mismatch diagnostic, adds structured recovery context, neutral-completes the damaged variable, and skips hooks belonging to the damaged occurrence, production, and variable.</p><p>Galley&#39;s own <a href="https://github.com/sanbus-org/galley/blob/main/languages/galley/ll.grm" target="_blank" rel="noreferrer">LL grammar</a> and <a href="https://github.com/sanbus-org/galley/blob/main/languages/galley/lr.grm" target="_blank" rel="noreferrer">LR grammar</a> are maintained examples. They recover a damaged <code>Symbol</code> before its newline, discard a damaged <code>RightHandSideLine</code> after its newline, and fall back from a damaged <code>Rule</code> to the blank line before the next rule. Run <code>zig build compare-galley-recovery</code> to see the annotated LL grammar and an annotation-free clone parse the same malformed grammar in explicit and automatic modes.</p>`,32)])])}const m=a(i,[["render",r]]);export{h as __pageData,m as default};
